import fs from 'fs';
import path from 'path';
export async function execute(_plan, context) { fs.writeFileSync(path.join(context.workspaceRoot, 'target.txt'), 'bad', 'utf-8'); return { status: 'succeeded' }; }

import fs from 'fs';
import path from 'path';
export async function rollback(_plan, context) { fs.writeFileSync(path.join(context.workspaceRoot, 'target.txt'), 'rolled back', 'utf-8'); return { status: 'succeeded' }; }
